'use client';

import * as React from 'react';

import type { TAudioElement } from 'platejs';
import type { PlateElementProps } from 'platejs/react';

import { useMediaState } from '@platejs/media/react';
import { ResizableProvider } from '@platejs/resizable';
import { PlateElement, withHOC } from 'platejs/react';

import { cn } from '@/lib/utils';
import { getElementSuggestionData } from '@/registry/ui/suggestion-node';
import { voidRemoveSuggestionClass } from '@/registry/ui/suggestion-node-static';

import { Caption, CaptionTextarea } from './caption';

export const AudioElement = withHOC(
  ResizableProvider,
  function AudioElement(props: PlateElementProps<TAudioElement>) {
    const { align = 'center', readOnly, unsafeUrl } = useMediaState();
    const isRemoveSuggestion =
      getElementSuggestionData(props.editor, props.element)?.type === 'remove';

    return (
      <PlateElement {...props} className="mb-1">
        <figure
          className="group relative cursor-default"
          contentEditable={false}
        >
          <div
            className={cn(
              'h-16 rounded-sm',
              isRemoveSuggestion && voidRemoveSuggestionClass
            )}
          >
            <audio className="size-full" src={unsafeUrl} controls />
          </div>

          <Caption style={{ width: '100%' }} align={align}>
            <CaptionTextarea
              className="h-20"
              readOnly={readOnly}
              placeholder="Write a caption..."
            />
          </Caption>
        </figure>
        {props.children}
      </PlateElement>
    );
  }
);

import * as React from 'react';

import type { TAudioElement } from 'platejs';
import type { SlateElementProps } from 'platejs/static';

import { SlateElement } from 'platejs/static';

import { cn } from '@/lib/utils';
import {
  getStaticElementSuggestionData,
  voidRemoveSuggestionClass,
} from '@/registry/ui/suggestion-node-static';

export function AudioElementStatic(props: SlateElementProps<TAudioElement>) {
  const isRemoveSuggestion =
    getStaticElementSuggestionData(props.element)?.type === 'remove';

  return (
    <SlateElement {...props} className="mb-1">
      <figure className="group relative cursor-default">
        <div
          className={cn(
            'h-16 rounded-sm',
            isRemoveSuggestion && voidRemoveSuggestionClass
          )}
        >
          <audio className="size-full" src={props.element.url} controls />
        </div>
      </figure>
      {props.children}
    </SlateElement>
  );
}
